import React, {type PropsWithChildren} from 'react'


import type {ISVGComponent} from "@lmb-it/kitsconcerto-types";
import {ResponsiveElement, useSeparator} from "../../factory";

const Svg = ({className, children, ref, ...props}: PropsWithChildren<ISVGComponent>) => {

    const {cssProps, nativeProps} = useSeparator<any>(props)


    return (
        <ResponsiveElement ref={ref}
                           additionalClasses={className}
                           cssProps={cssProps}
                           additionalStyles={{
                               // @ts-ignore
                               display: 'inline-block',
                               lineHeight: '1rem',
                               flexShrink: 0,
                               verticalAlign: 'middle',
                               marginInline: '2px',
                               width: '1.5rem',
                               height: '1.5rem'
                           }}
                           nativeProps={nativeProps}
                           as={"Svg"}
                           children={children}/>
    )
}

export default Svg;
